import{_ as a,o as i,c as r,al as l}from"./chunks/framework.BOATtE-F.js";const g=JSON.parse('{"title":"Preview and Sharing","description":"","frontmatter":{"prev":{"text":"Configuration","link":"/en/posts/docs/ageratum/09-config"}},"headers":[],"relativePath":"en/posts/docs/ageratum/10-preview-and-sharing.md","filePath":"en/posts/docs/ageratum/10-preview-and-sharing.md","lastUpdated":1774974346000}'),n={name:"en/posts/docs/ageratum/10-preview-and-sharing.md"};function o(t,e,s,d,h,c){return i(),r("div",null,[...e[0]||(e[0]=[l(`<h1 id="preview-and-sharing" tabindex="-1">Preview and Sharing <a class="header-anchor" href="#preview-and-sharing" aria-label="Permalink to “Preview and Sharing”">​</a></h1><p>This page covers two collaboration workflows in Ageratum: <strong>local preview</strong> (iterate docs quickly) and <strong>guide sharing</strong> (send your current page to other players).</p><hr><h2 id="_1-local-preview-mode" tabindex="-1">1. Local Preview Mode <a class="header-anchor" href="#_1-local-preview-mode" aria-label="Permalink to “1. Local Preview Mode”">​</a></h2><p>Preview mode lets you iterate Markdown documents without restarting the game or reloading resource packs.</p><h3 id="enable-preview" tabindex="-1">Enable Preview <a class="header-anchor" href="#enable-preview" aria-label="Permalink to “Enable Preview”">​</a></h3><p>Set these in <code>ageratum-client.toml</code>:</p><div class="language-toml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enablePreview = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">previewPath = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ageratum_preview&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="command-entry" tabindex="-1">Command Entry <a class="header-anchor" href="#command-entry" aria-label="Permalink to “Command Entry”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/ageratum preview</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This command tries to open:</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;minecraft_dir&gt;/&lt;previewPath&gt;/index.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>With defaults, that is <code>&lt;minecraft_dir&gt;/ageratum_preview/index.md</code>.</p><h3 id="refresh-behavior" tabindex="-1">Refresh Behavior <a class="header-anchor" href="#refresh-behavior" aria-label="Permalink to “Refresh Behavior”">​</a></h3><ul><li>After the screen opens, preview checks file changes periodically (last-modified time + file size).</li><li>Poll interval is about <code>500ms</code>.</li><li>When changes are detected, markdown is re-parsed and reader position is preserved as much as possible.</li></ul><h3 id="preview-path-rules" tabindex="-1">Preview Path Rules <a class="header-anchor" href="#preview-path-rules" aria-label="Permalink to “Preview Path Rules”">​</a></h3><ul><li>Preview namespace is fixed as <code>ageratum_review</code> (internal use).</li><li>File arguments are normalized: <ul><li>empty -&gt; <code>index</code></li><li><code>\\\\</code> -&gt; <code>/</code></li><li>remove leading <code>/</code></li><li>strip <code>.md</code> then re-append consistently</li><li>ignore <code>.</code> and resolve <code>..</code> back to parent</li><li>lowercase each path segment</li></ul></li></ul><p>This keeps behavior consistent across platforms.</p><hr><h2 id="_2-guide-sharing-workflow" tabindex="-1">2. Guide Sharing Workflow <a class="header-anchor" href="#_2-guide-sharing-workflow" aria-label="Permalink to “2. Guide Sharing Workflow”">​</a></h2><p>Ageratum provides a network-based flow for sharing your current guide page with other players.</p><h3 id="network-payloads" tabindex="-1">Network Payloads <a class="header-anchor" href="#network-payloads" aria-label="Permalink to “Network Payloads”">​</a></h3><h4 id="openguidepayload-server-client" tabindex="-1"><code>OpenGuidePayload</code> (Server -&gt; Client) <a class="header-anchor" href="#openguidepayload-server-client" aria-label="Permalink to “OpenGuidePayload (Server -&gt; Client)”">​</a></h4><ul><li>Field: <code>location: ResourceLocation</code></li><li>Purpose: tell target client to open a document</li></ul><h4 id="shareguidepayload-client-server" tabindex="-1"><code>ShareGuidePayload</code> (Client -&gt; Server) <a class="header-anchor" href="#shareguidepayload-client-server" aria-label="Permalink to “ShareGuidePayload (Client -&gt; Server)”">​</a></h4><ul><li>Fields: <ul><li><code>location: ResourceLocation</code></li><li><code>anchor: String</code></li><li><code>sameTeam: boolean</code></li></ul></li><li>Purpose: ask server to broadcast a clickable share message</li></ul><h3 id="server-handling" tabindex="-1">Server Handling <a class="header-anchor" href="#server-handling" aria-label="Permalink to “Server Handling”">​</a></h3><p><code>ServerPayloadHandler.handleShareGuide</code>:</p><ol><li>Gets sender and current online players.</li><li>Applies team filter when <code>sameTeam</code> is true.</li><li>Builds a system message with a clickable button.</li><li>Click executes <code>/ageratum &quot;namespace&quot; &quot;path&quot; [anchor]</code> on receiver side.</li></ol><h3 id="team-only-sharing-config" tabindex="-1">Team-only Sharing Config <a class="header-anchor" href="#team-only-sharing-config" aria-label="Permalink to “Team-only Sharing Config”">​</a></h3><p><code>shareGuideOnlyInTeam</code> in <code>ageratum-client.toml</code> controls the <code>sameTeam</code> behavior. For public servers, enabling this is usually safer.</p><hr><h2 id="_3-language-fallback-and-sharing" tabindex="-1">3. Language Fallback and Sharing <a class="header-anchor" href="#_3-language-fallback-and-sharing" aria-label="Permalink to “3. Language Fallback and Sharing”">​</a></h2><p>Both normal opening and share-based opening use the same lookup rule:</p><ol><li>Try client language first (for example <code>zh_cn</code>).</li><li>Fall back to <code>en_us</code> if not found.</li></ol><p>So shared links can stay language-neutral while still opening localized pages when available.</p><hr><h2 id="_4-recommended-team-workflow" tabindex="-1">4. Recommended Team Workflow <a class="header-anchor" href="#_4-recommended-team-workflow" aria-label="Permalink to “4. Recommended Team Workflow”">​</a></h2><h3 id="solo-writing" tabindex="-1">Solo Writing <a class="header-anchor" href="#solo-writing" aria-label="Permalink to “Solo Writing”">​</a></h3><ol><li>Enable <code>enablePreview</code>.</li><li>Edit documents under <code>previewPath</code>.</li><li>Run <code>/ageratum preview</code> for live verification.</li><li>Move finalized files into <code>assets/&lt;modid&gt;/ageratum/&lt;lang&gt;/...</code>.</li></ol><h3 id="multiplayer-review" tabindex="-1">Multiplayer Review <a class="header-anchor" href="#multiplayer-review" aria-label="Permalink to “Multiplayer Review”">​</a></h3><ol><li>Author iterates locally in preview mode.</li><li>Share the target page to testers.</li><li>Testers click the system message and jump directly to the same document.</li><li>Collect feedback and continue iterating.</li></ol><hr><h2 id="_5-faq" tabindex="-1">5. FAQ <a class="header-anchor" href="#_5-faq" aria-label="Permalink to “5. FAQ”">​</a></h2><h3 id="q1-ageratum-preview-does-nothing" tabindex="-1">Q1: <code>/ageratum preview</code> does nothing <a class="header-anchor" href="#q1-ageratum-preview-does-nothing" aria-label="Permalink to “Q1: /ageratum preview does nothing”">​</a></h3><p>Check first:</p><ul><li><code>enablePreview</code> is <code>true</code></li><li><code>&lt;minecraft_dir&gt;/&lt;previewPath&gt;/index.md</code> exists</li><li>file encoding is UTF-8</li></ul><h3 id="q2-file-changed-but-screen-did-not-refresh" tabindex="-1">Q2: File changed but screen did not refresh <a class="header-anchor" href="#q2-file-changed-but-screen-did-not-refresh" aria-label="Permalink to “Q2: File changed but screen did not refresh”">​</a></h3><ul><li>wait about 0.5~1 second (polling)</li><li>ensure your editor actually wrote the file to disk</li><li>ensure the file is under <code>previewPath</code></li></ul><h3 id="q3-shared-guide-cannot-be-opened-by-others" tabindex="-1">Q3: Shared guide cannot be opened by others <a class="header-anchor" href="#q3-shared-guide-cannot-be-opened-by-others" aria-label="Permalink to “Q3: Shared guide cannot be opened by others”">​</a></h3><ul><li>verify both sides have required assets/docs</li><li>verify target page exists for receiver language (or has <code>en_us</code> fallback)</li><li>if team-only sharing is enabled, verify both players are on the same team</li></ul><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to “See Also”">​</a></h2><ul><li><a href="./09-config.html">Configuration</a></li><li><a href="./01-getting-started.html">Getting Started</a></li><li><a href="./07-api-reference.html">API Reference</a></li></ul>`,54)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
